import org.owasp.esapi.ESAPI;
import org.owasp.esapi.codecs.HTMLEntityCodec;

public class SecureXSSPrevention {
    public static void main(String[] args) {
        // Simulating user input
        String userInput = "<script>alert('XSS attack!')</script>";

        // Encoding user input to prevent XSS attacks
        HTMLEntityCodec htmlEncoder = new HTMLEntityCodec();
        String encodedUserInput = htmlEncoder.encodeForHTML(userInput);

        // Creating the output HTML with properly encoded user input
        String outputHtml = "<html><body>" + encodedUserInput + "</body></html>";

        // Displaying the output HTML
        System.out.println(outputHtml);
    }
}

